import * as notion from 'notion-types';
import { FetchOptions } from 'ofetch';

interface SignedUrlRequest {
    permissionRecord: PermissionRecord;
    url: string;
}
interface PermissionRecord {
    table: string;
    id: notion.ID;
}
interface SignedUrlResponse {
    signedUrls: string[];
}

/**
 * Main Notion API client.
 */
declare class NotionAPI {
    private readonly _apiBaseUrl;
    private readonly _authToken?;
    private readonly _activeUser?;
    private readonly _userTimeZone;
    private readonly _ofetchOptions?;
    /**
     * Constructor for the NotionAPI class.
     * @param options - Configuration options.
     * @param options.apiBaseUrl - The base URL of the Notion API. Defaults to `https://www.notion.so/api/v3`.
     * @param options.authToken - The authentication token for the Notion API. Defaults to undefined.
     * @param options.activeUser - The active user for the Notion API. Defaults to undefined.
     * @param options.userTimeZone - The time zone for the Notion API. Defaults to `America/New_York`.
     * @param options.ofetchOptions - The HTTP options to use for the underlying `ofetch` requests. Defaults to undefined.
     */
    constructor({ apiBaseUrl, authToken, activeUser, userTimeZone, ofetchOptions }?: {
        apiBaseUrl?: string;
        authToken?: string;
        userLocale?: string;
        userTimeZone?: string;
        activeUser?: string;
        ofetchOptions?: FetchOptions;
    });
    /**
     * Fetch a Notion page's content, including all async blocks, collection queries, and signed urls.
     *
     * @param pageId - The ID of the Notion page to fetch. May be a page ID, UUID, or URL.
     * @param options - Optional configuration options.
     * @param options.concurrency - The max number of concurrent Notion API requests to make. Defaults to `3`.
     * @param options.fetchMissingBlocks - Whether to fetch additional missing blocks. Defaults to `true`.
     * @param options.fetchCollections - Whether to fetch collections and their associated views. Defaults to `true`.
     * @param options.signFileUrls - Whether to sign file URLs. Defaults to `true`.
     * @param options.chunkLimit - The number of chunks to fetch. Defaults to `100`.
     * @param options.chunkNumber - The number of the first chunk to fetch. Defaults to `0`.
     * @param options.throwOnCollectionErrors - Whether to throw on collection errors. Defaults to `false`.
     * @param options.collectionReducerLimit - The max number of collection reducers to fetch. Defaults to `999`.
     * @param options.fetchRelationPages - Whether to fetch relation pages. Defaults to `false`.
     * @param options.ofetchOptions - The HTTP options to use for the underlying `ofetch` requests. Defaults to `undefined`.
     *
     * @returns The content of the Notion page as an `ExtendedRecordMap`.
     */
    getPage(pageId: string, { concurrency, fetchMissingBlocks, fetchCollections, signFileUrls, chunkLimit, chunkNumber, throwOnCollectionErrors, collectionReducerLimit, fetchRelationPages, ofetchOptions }?: {
        concurrency?: number;
        fetchMissingBlocks?: boolean;
        fetchCollections?: boolean;
        signFileUrls?: boolean;
        chunkLimit?: number;
        chunkNumber?: number;
        throwOnCollectionErrors?: boolean;
        collectionReducerLimit?: number;
        fetchRelationPages?: boolean;
        ofetchOptions?: FetchOptions;
    }): Promise<notion.ExtendedRecordMap>;
    /**
     * Fetches relation pages from the Notion API.
     *
     * @param recordMap - The record map to fetch relation pages from.
     * @param ofetchOptions - The HTTP options to use for the underlying `ofetch` requests.
     *
     * @returns The relation pages as a `BlockMap`.
     */
    fetchRelationPages: (recordMap: notion.ExtendedRecordMap, ofetchOptions: FetchOptions | undefined) => Promise<notion.BlockMap>;
    extractRelationPageIdsFromBlock: (blockValue: any, collectionSchema: any) => Set<string>;
    addSignedUrls({ recordMap, contentBlockIds, ofetchOptions }: {
        recordMap: notion.ExtendedRecordMap;
        contentBlockIds?: string[];
        ofetchOptions?: FetchOptions;
    }): Promise<void>;
    getPageRaw(pageId: string, { ofetchOptions, chunkLimit, chunkNumber }?: {
        chunkLimit?: number;
        chunkNumber?: number;
        ofetchOptions?: FetchOptions;
    }): Promise<notion.PageChunk>;
    getCollectionData(collectionId: string, collectionViewId: string, collectionView?: any, { limit, searchQuery, userTimeZone, loadContentCover, spaceId, ofetchOptions }?: {
        type?: notion.CollectionViewType;
        limit?: number;
        searchQuery?: string;
        userTimeZone?: string;
        userLocale?: string;
        loadContentCover?: boolean;
        spaceId?: string;
        ofetchOptions?: FetchOptions;
    }): Promise<notion.CollectionInstance>;
    getUsers(userIds: string[], ofetchOptions?: FetchOptions): Promise<notion.RecordValues<notion.User>>;
    getBlocks(blockIds: string[], ofetchOptions?: FetchOptions): Promise<notion.PageChunk>;
    getSignedFileUrls(urls: SignedUrlRequest[], ofetchOptions?: FetchOptions): Promise<SignedUrlResponse>;
    search(params: notion.SearchParams, ofetchOptions?: FetchOptions): Promise<notion.SearchResults>;
    fetch<T>({ endpoint, body, ofetchOptions, headers: clientHeaders }: {
        endpoint: string;
        body: object;
        ofetchOptions?: FetchOptions;
        headers?: any;
    }): Promise<T>;
}

export { NotionAPI, type PermissionRecord, type SignedUrlRequest, type SignedUrlResponse };
